#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        if (scanf("%d", &N) != 1) N = 0;
        printf("%d\n", N * 2);
    }
    return 0;
}

